def build_solve_full\(label, add_생휴=False, add_수면=False, add_병가_count=False\):
    import json
    from datetime import date, timedelta
    from ortools.sat.python import cp_model
    from engine.models import get_sleep_partner_month

    model = cp_model.CpModel\(\)
    shifts = {}
    for ni in range\(num_nurses\):
        for di in range\(num_days\):
            for si in range\(NUM_TYPES\):
                shifts[\(ni,di,si\)] = model.new_bool_var\(f's_{ni}_{di}_{si}'\)

    # H1
    for ni in range\(num_nurses\):
        for di in range\(num_days\):
            model.add\(sum\(shifts[\(ni,di,si\)] for si in range\(NUM_TYPES\)\)==1\)

    # H2
    for di in range\(num_days\):
        model.add\(sum\(shifts[\(ni,di,_D\)] for ni in range\(num_nurses\)\)==rules.daily_D\)
        if 중2_nurses and wd\(di\)<5:
            model.add\(sum\(shifts[\(ni,di,si\)] for ni in 중2_nurses for si in M_FAMILY\)==rules.daily_M\)
        else:
            model.add\(sum\(shifts[\(ni,di,si\)] for ni in range\(num_nurses\) for si in M_FAMILY\)==0\)
        model.add\(sum\(shifts[\(ni,di,_E\)] for ni in range\(num_nurses\)\)==rules.daily_E\)
        model.add\(sum\(shifts[\(ni,di,_N\)] for ni in range\(num_nurses\)\)==rules.daily_N\)

    # H2a
    for ni in [ni for ni,n in enumerate\(nurses\) if n.role!='중2']:
        for di in range\(num_days\): model.add\(shifts[\(ni,di,_중2\)]==0\)
    _iol = {_D9:set\(\), _D1:set\(\), _중1:set\(\)}
    for r in requests_list:
        if r.is_hard and r.code in \('D9','D1','중1'\) and r.nurse_id in nurse_idx:
            ni=nurse_idx[r.nurse_id]; di=r.day-1
            if 0<=di<num_days and r.code in NAME_TO_IDX: _iol[NAME_TO_IDX[r.code]].add\(\(ni,di\)\)
    for si in \(_D9,_D1,_중1\):
        for ni in range\(num_nurses\):
            for di in range\(num_days\):
                if \(ni,di\) not in _iol[si]: model.add\(shifts[\(ni,di,si\)]==0\)

    nurse_병가_span = {}
    for ni,nurse in enumerate\(nurses\):
        sick_days = sorted\(r.day-1 for r in requests_list
                          if r.nurse_id==nurse.id and r.is_hard and r.code=='병가' and 0<=r.day-1<num_days\)
        nurse_병가_span[ni] = \(sick_days[0],sick_days[-1]\) if sick_days else None
    def in_span\(ni,di\):
        sp=nurse_병가_span[ni]; return sp is not None and sp[0]<=di<=sp[1]

    fixed_off_days = set\(\)
    for ni,nurse in enumerate\(nurses\):
        if nurse.fixed_weekly_off is not None:
            for di in range\(num_days\):
                if wd\(di\)==nurse.fixed_weekly_off: fixed_off_days.add\(\(ni,di\)\)

    # H8
    off_week_used={}; menst_hard_used={}
    for r in requests_list:
        if not r.is_hard: continue
        if r.nurse_id not in nurse_idx: continue
        ni=nurse_idx[r.nurse_id]; di=r.day-1
        if di<0 or di>=num_days: continue
        if r.code=='생휴':
            if nurses[ni].is_male: continue
            _pm=len\({\(start_date+timedelta\(days=d\)\).month for d in range\(num_days\)}\)
            _mm=_pm-\(1 if nurses[ni].menstrual_used else 0\)
            menst_hard_used.setdefault\(r.nurse_id,0\)
            if menst_hard_used[r.nurse_id]>=_mm: continue
            menst_hard_used[r.nurse_id]+=1
        if r.code=='주' and in_span\(ni,di\): continue
        if r.code=='주':
            if nurses[ni].fixed_weekly_off is None: continue
            if wd\(di\)!=nurses[ni].fixed_weekly_off: continue
        if r.code=='법휴': continue
        if r.code=='OFF':
            req=2 if nurses[ni].is_4day_week else 1
            wk=di//7; key=\(ni,wk\)
            off_week_used.setdefault\(key,0\)
            if off_week_used[key]>=req: continue
            off_week_used[key]+=1
        if r.code in NAME_TO_IDX: model.add\(shifts[\(ni,di,NAME_TO_IDX[r.code]\)]==1\)

    # H9
    for r in requests_list:
        if not r.is_exclude or r.nurse_id not in nurse_idx: continue
        ni=nurse_idx[r.nurse_id]; di=r.day-1
        if di<0 or di>=num_days: continue
        if r.excluded_shift=='D':
            for si in D_FAMILY: model.add\(shifts[\(ni,di,si\)]==0\)
        elif r.excluded_shift=='E':
            for si in E_FAMILY: model.add\(shifts[\(ni,di,si\)]==0\)
        elif r.excluded_shift=='N': model.add\(shifts[\(ni,di,_N\)]==0\)

    # H10
    for ni,nurse in enumerate\(nurses\):
        if nurse.fixed_weekly_off is not None:
            for di in range\(num_days\):
                if wd\(di\)==nurse.fixed_weekly_off:
                    if in_span\(ni,di\): model.add\(shifts[\(ni,di,_주\)]==0\); model.add\(shifts[\(ni,di,_병가\)]==1\)
                    else: model.add\(shifts[\(ni,di,_주\)]==1\)
                else: model.add\(shifts[\(ni,di,_주\)]==0\)
        else:
            for di in range\(num_days\): model.add\(shifts[\(ni,di,_주\)]==0\)
    for ni in range\(num_nurses\):
        for di in range\(num_days\): model.add\(shifts[\(ni,di,_법휴\)]==0\)

    # H11
    nurse_committed={ni:set\(\) for ni in range\(num_nurses\)}
    for r in requests_list:
        if not r.is_hard or r.nurse_id not in nurse_idx: continue
        ni_r=nurse_idx[r.nurse_id]; di_r=r.day-1
        if 0<=di_r<num_days and r.code in NAME_TO_IDX and r.code!='OFF': nurse_committed[ni_r].add\(di_r\)
    for ni,nurse in enumerate\(nurses\):
        if nurse.fixed_weekly_off is not None:
            for di in range\(num_days\):
                if wd\(di\)==nurse.fixed_weekly_off: nurse_committed[ni].add\(di\)
    for ni in range\(num_nurses\):
        req_off=2 if nurses[ni].is_4day_week else 1; committed=nurse_committed[ni]
        for w_start in range\(0,num_days,7\):
            w_end=min\(w_start+7,num_days\); off_sum=sum\(shifts[\(ni,di,_OFF\)] for di in range\(w_start,w_end\)\)
            if w_end-w_start<4: model.add\(off_sum<=req_off\); continue
            avail=sum\(1 for di in range\(w_start,w_end\) if di not in committed\)
            model.add\(off_sum==min\(req_off,avail\)\)

    # H12, H13, H14
    chiefs=[ni for ni,n in enumerate\(nurses\) if n.grade=='책임']
    if chiefs:
        for di in range\(num_days\):
            for si in [_D,_E,_N]: model.add\(sum\(shifts[\(ni,di,si\)] for ni in chiefs\)>=1\)
    seniors=[ni for ni,n in enumerate\(nurses\) if n.grade in \('책임','서브차지'\)]
    if seniors:
        for di in range\(num_days\):
            model.add\(sum\(shifts[\(ni,di,si\)] for ni in seniors for si in D_FAMILY\)>=2\)
            model.add\(sum\(shifts[\(ni,di,si\)] for ni in seniors for si in E_FAMILY\)>=2\)
            model.add\(sum\(shifts[\(ni,di,_N\)] for ni in seniors\)>=2\)
    from engine.models import ROLE_TIERS
    for tr,md,me,mn in ROLE_TIERS:
        ti=[ni for ni,n in enumerate\(nurses\) if n.role in tr]
        if not ti: continue
        for di in range\(num_days\):
            model.add\(sum\(shifts[\(ni,di,_D\)] for ni in ti\)<=md\)
            model.add\(sum\(shifts[\(ni,di,_E\)] for ni in ti\)<=me\)
            model.add\(sum\(shifts[\(ni,di,_N\)] for ni in ti\)<=mn\)

    # Boundary
    for ni,nurse in enumerate\(nurses\):
        tail=nurse.prev_tail_shifts
        if not tail: continue
        tl=len\(tail\)
        off_set={'OFF','주','법휴','수면','생휴','휴가','병가','특휴','공가','경가','보수','POFF','필수','번표'}
        if rules.ban_reverse_order and tl>=1:
            last=tail[-1]
            if last in NAME_TO_IDX:
                li=NAME_TO_IDX[last]
                if li in SHIFT_LEVEL:
                    for sj in WORK_INDICES:
                        if sj in SHIFT_LEVEL and SHIFT_LEVEL[li]>SHIFT_LEVEL[sj]: model.add\(shifts[\(ni,0,sj\)]==0\)
        if tl>=2:
            t2,t1=tail[-2],tail[-1]
            if t2=='N' and t1 in off_set:
                for si in D_FAMILY+M_FAMILY: model.add\(shifts[\(ni,0,si\)]==0\)
        if tl>=1 and tail[-1]=='N' and num_days>=2:
            for si in D_FAMILY+M_FAMILY: model.add\(sum\(shifts[\(ni,0,oi\)] for oi in ALL_OFF\)+shifts[\(ni,1,si\)]<=1\)
        if tl>=1 and tail[-1]=='N':
            for si in \(_보수,_필수,_번표\): model.add\(shifts[\(ni,0,si\)]==0\)
        _ws={'D','E','N','중2'}
        cw=0
        for s in reversed\(tail\):
            if s in _ws: cw+=1
            else: break
        if cw>0:
            rem=rules.max_consecutive_work-cw
            if rem<=0: model.add\(sum\(shifts[\(ni,0,oi\)] for oi in ALL_OFF\)>=1\)
            else:
                w=min\(rem+1,num_days\)
                if w>0: model.add\(sum\(shifts[\(ni,dd,oi\)] for dd in range\(w\) for oi in ALL_OFF\)>=1\)
        cn=0
        for s in reversed\(tail\):
            if s=='N': cn+=1
            else: break
        if cn>0:
            remn=rules.max_consecutive_N-cn
            if remn<=0: model.add\(shifts[\(ni,0,_N\)]==0\)
            else:
                wn=min\(remn+1,num_days\); model.add\(sum\(shifts[\(ni,dd,_N\)] for dd in range\(wn\)\)<=remn\) if wn>0 else None
        oa=rules.off_after_2N
        if tl>=2 and tail[-2]=='N' and tail[-1]=='N':
            for k in range\(oa\):
                if k<num_days: model.add\(sum\(shifts[\(ni,k,oi\)] for oi in ALL_OFF\)>=1\)
        elif tl>=1 and tail[-1]=='N':
            for k in range\(oa\):
                if 1+k<num_days: model.add\(shifts[\(ni,0,_N\)]<=sum\(shifts[\(ni,1+k,oi\)] for oi in ALL_OFF\)\)

    # H20 with skip logic
    중2e=any\(n.role=='중2' for n in nurses\); 중2pw=rules.daily_M if 중2e else 0
    nwd=sum\(1 for di in range\(num_days\) if wd\(di\)<5\)
    tw=\(nwd*\(rules.daily_D+중2pw+rules.daily_E+rules.daily_N\)+\(num_days-nwd\)*\(rules.daily_D+rules.daily_E+rules.daily_N\)\)
    to=num_nurses*num_days-tw; e4=5; n4=sum\(1 for n in nurses if n.is_4day_week\)
    bo=round\(\(to-e4*n4\)/max\(num_nurses,1\)\); ft=bo+e4
    def exp_off\(ni\):
        nid=nurses[ni].id
        ho=sum\(1 for r in requests_list if r.nurse_id==nid and r.is_hard and 1<=r.day<=num_days\)
        req=2 if nurses[ni].is_4day_week else 1
        span=nurse_병가_span[ni]; nfwo=nurses[ni].fixed_weekly_off
        for w in range\(0,num_days,7\):
            we=min\(w+7,num_days\)
            if we-w<4: continue
            if span and all\(span[0]<=di<=span[1] for di in range\(w,we\)\): continue
            if span and any\(span[0]<=di<=span[1] for di in range\(w,we\)\):
                av=sum\(1 for di in range\(w,we\) if not\(span[0]<=di<=span[1]\) and not\(nfwo is not None and wd\(di\)==nfwo\)\)
                ho+=min\(req,av\)
            else: ho+=req
        return ho
    for ni in range\(num_nurses\):
        is4=nurses[ni].is_4day_week; target=ft if is4 else bo; ub=target+2
        if exp_off\(ni\)>ub: continue
        os=sum\(shifts[\(ni,di,oi\)] for di in range\(num_days\) for oi in ALL_OFF\)
        if is4: model.add\(os>=ft-2\); model.add\(os<=ft+2\)
        else: model.add\(os>=bo-2\); model.add\(os<=bo+2\)

    # Special offs
    _pm=len\({\(start_date+timedelta\(days=di\)\).month for di in range\(num_days\)}\)

    for ni,nurse in enumerate\(nurses\):
        hard_counts = {}
        for code,idx in [\('생휴',_생휴\),\('수면',_수면\),\('휴가',_휴가\),\('병가',_병가\),
                         \('특휴',_특휴\),\('공가',_공가\),\('경가',_경가\),\('보수',_보수\),\('필수',_필수\),\('번표',_번표\)]:
            hard_counts[idx]=sum\(1 for r in requests_list
                                if r.is_hard and r.nurse_id==nurse.id and r.code==code
                                and 1<=r.day<=num_days and \(ni,r.day-1\) not in fixed_off_days\)
        span=nurse_병가_span[ni]
        if span is not None:
            ss,se=span
            hard_counts[_병가]+=sum\(1 for di in range\(num_days\) if \(ni,di\) in fixed_off_days and ss<=di<=se\)

        if add_생휴:
            max_menst=max\(0,_pm-\(1 if nurse.menstrual_used else 0\)\)
            menst_sum=sum\(shifts[\(ni,di,_생휴\)] for di in range\(num_days\)\)
            if nurse.is_male: model.add\(menst_sum==0\)
            elif hard_counts[_생휴]>0: model.add\(menst_sum==min\(hard_counts[_생휴],max_menst\)\)
            elif rules.menstrual_leave and max_menst>0: model.add\(menst_sum==max_menst\)
            else: model.add\(menst_sum==0\)
            if not nurse.is_male:
                dm={}
                for di in range\(num_days\): dm.setdefault\(\(start_date+timedelta\(days=di\)\).month,[]\).append\(di\)
                for m,mdays in dm.items\(\):
                    ms=sum\(shifts[\(ni,di,_생휴\)] for di in mdays\)
                    is_start=\(start_date+timedelta\(days=mdays[0]\)\).month==start_date.month
                    if nurse.menstrual_used and is_start: model.add\(ms==0\)
                    else: model.add\(ms<=1\)

        if add_수면:
            hs=hard_counts[_수면]; ss=sum\(shifts[\(ni,di,_수면\)] for di in range\(num_days\)\)
            if hs>0: model.add\(ss==hs\)
            elif nurse.pending_sleep: model.add\(ss==1\)
            else: model.add\(ss==0\)

        if add_병가_count:
            model.add\(sum\(shifts[\(ni,di,_병가\)] for di in range\(num_days\)\)==hard_counts[_병가]\)

        # Always zero out unused special offs
        if not add_생휴:
            model.add\(sum\(shifts[\(ni,di,_생휴\)] for di in range\(num_days\)\)==0\)
        if not add_수면:
            model.add\(sum\(shifts[\(ni,di,_수면\)] for di in range\(num_days\)\)==0\)
        for idx in [_특휴,_공가,_경가,_보수,_필수,_번표]:
            hc=hard_counts[idx] if add_병가_count else 0
            model.add\(sum\(shifts[\(ni,di,idx\)] for di in range\(num_days\)\)==hc\)
        if not nurse.is_pregnant:
            for di in range\(num_days\): model.add\(shifts[\(ni,di,_POFF\)]==0\)

    solver=cp_model.CpSolver\(\)
    solver.parameters.max_time_in_seconds=15; solver.parameters.num_workers=4
    r=solver.solve\(model\)
    feasible=r in \(cp_model.FEASIBLE,cp_model.OPTIMAL\)
    print\(f'  {label}: {\\"FEASIBLE\\" if feasible else solver.status_name\(r\)}'\)
    return feasible

